2778         APInt Dist = LHSOffset - RHSOffset;
2779         if (Dist.isNonNegative() ? Dist.ult(LHSSize) : (-Dist).ult(RHSSize))
2780           return ConstantInt::get(getCompareTy(LHS),
2781                                   !CmpInst::isTrueWhenEqual(Pred));
2782       }
2783     }
